import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"36. Overtime","description":"","frontmatter":{"title":"36. Overtime","eba":"Doctors in Training 2022-2026","topics":["hours","overtime","rosters","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/36-overtime.md","filePath":"ebas/doctors-in-training/hours-of-work/36-overtime.md"}'),i={name:"ebas/doctors-in-training/hours-of-work/36-overtime.md"};function s(n,e,h,d,p,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_36-overtime" tabindex="-1">36. Overtime <a class="header-anchor" href="#_36-overtime" aria-label="Permalink to &quot;36. Overtime&quot;">​</a></h1><p>The purpose of this clause is to ensure that all time worked is paid and that timesheets (or equivalent) are submitted within the time required by the Health Service to ensure that Health Services have information relevant to the provision of safe hours.</p><p><strong>36.1</strong> The provisions of this clause 36 are to be read in conjunction with <a href="/eba/ebas/doctors-in-training/hours-of-work/33-hours-of-work.html">clause 33</a> (Hours of Work).</p><p><strong>36.2</strong> Definition</p><p><strong>(a)</strong> Hours worked in excess of ordinary hours per week pursuant to subclause 33.1 will be deemed overtime.</p><p><strong>(b)</strong> Overtime may be either rostered or unrostered.</p><p><strong>36.3</strong> Overtime rates</p><p>Where Doctor works overtime the Health Service must, subject to subclauses 36.4 (Part-time doctors) and 36.5 (Conversion of overtime to personal / carer’s leave) pay the Doctor overtime rates as follows:</p><p>For overtime worked on Full-time and part- Casual overtime time overtime rate rate1</p><p>% of ordinary hourly rate</p><p>Monday to Saturday—first 2 hours 150% 175%</p><p>Monday to Saturday—after 2 hours 200% 225%</p><p>Sunday—all day 200% 225%</p><p>Public holidays—all day 250% 275%</p><p>Includes 25% casual loading provided in <a href="/eba/ebas/doctors-in-training/doctor-employment/19-casual-employment.html">clause 19.3</a>.</p><p><strong>36.4</strong> Part-time doctors</p><p>A part-time Doctor directed by a Health Service to work rostered hours in excess of their contracted hours, will be paid overtime for those hours except where:</p><p><strong>(a)</strong> A part time Doctor who is offered and accepts additional rostered hours will be paid their ordinary rate of pay until their total weekly hours of work exceed the full-time ordinary hours for their classification prescribed in <a href="/eba/ebas/doctors-in-training/hours-of-work/33-hours-of-work.html">clause 33</a> (Hours of Work).</p><p><strong>36.5</strong> Conversion of overtime to personal / carer’s leave</p><p>Overtime may be converted into carer’s leave in accordance with subclause 61.3(c)</p><p><strong>36.6</strong> Approval and Payment of Overtime</p><p><strong>(a)</strong> Overtime must, where reasonably practicable, be authorised in advance, subject to the provisions below.</p><p><strong>(b)</strong> Rostered overtime is authorised in advance.</p><p><strong>(c)</strong> Unrostered overtime should, where reasonably practicable, be authorised in advance. Where unrostered overtime is not authorised in advance, it will be deemed to be authorised where it satisfies the requirements of the Health Service’s Unrostered Overtime Protocol.</p><p><strong>(d)</strong> Where unrostered overtime is neither approved in advance nor approved in accordance with the Health Service’s Unrostered Overtime Protocol, the Doctor will be paid for the overtime hours worked where it is submitted on a timesheet (or equivalent) within the time required by the Health Service save that:</p><p><strong>(i)</strong> if there is a dispute as to whether the hours were worked by the Doctor, the Health Service and Doctor will seek to resolve that dispute through the Dispute Settling Procedures of this Agreement; and</p><p><strong>(ii)</strong> nothing in this term limits the ability of the Health Service to review the reason the overtime was worked and to take reasonable management steps to reduce the need for overtime to be worked so far as is practicable, including having regard for its obligations under <a href="/eba/ebas/doctors-in-training/hours-of-work/41-workload-management-and-review.html">clause 41</a> (Workload Management and Review) of this Agreement,</p><p><strong>36.7</strong> Unrostered Overtime - Protocols</p><p><strong>(a)</strong> Each Health Service shall have an Unrostered Overtime Protocol (Protocol) where overtime that has not been authorised in advance but has been worked will be deemed authorised and paid if it meets appropriate, clearly defined criteria.</p><p><strong>(b)</strong> The Protocol will be structured on the following basis:</p><p><strong>(i)</strong> the Doctor has performed the overtime due to a demonstrable clinical need and that need could not have been met by some other means;</p><p><strong>(ii)</strong> it was not practicable for the authorisation of the overtime to have been made in advance of the Doctor performing the work;</p><p><strong>(iii)</strong> the Doctor has claimed for retrospective authorisation of overtime as soon as practicable after the overtime was worked and no later than the completion of that pay fortnight;</p><p><strong>(iv)</strong> the Doctor has recorded the reason for working the overtime and the duties performed in a form capable of Health Service audit and review;</p><p><strong>(v)</strong> the claim for overtime must be reviewed the person authorised by the Health Service to do so within 14 days of the claim being submitted; and</p><p><strong>(vi)</strong> where unrostered overtime is worked and not approved in advance or consistent with this Unrostered Overtime Protocol, it will be paid but the Health Service may review the reason for the overtime with a view to ensuring safe working hours.</p><p><strong>(c)</strong> <a href="/eba/ebas/doctors-in-training/doctor-employment/27-orientation-on-appointment.html">Clause 27.2</a>(h) of this Agreement provides that a copy of the Protocol shall be included in the Unit Handbook.</p><p><strong>36.8</strong> Late lodgement of overtime</p><p><strong>(a)</strong> Where unrostered Overtime is worked but not submitted within the time required by the Health Service and was:</p><p><strong>(i)</strong> not authorised in advance; or</p><p><strong>(ii)</strong> not worked consistent with the Protocol,</p><p>the Doctor will be paid overtime subject to providing reasonable evidence of the hours worked to the Health Service.</p><p><strong>(b)</strong> Where a Doctor does not submit a claim for overtime within the timeframe required by the Health Service as described at (a) above, the Health Service may seek an explanation and take reasonable management steps as a result.</p><p>Plain language terms: OT, extra hours, double time.</p>',44)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
